arguments.file_text:
Span<nint> values = stackalloc nint[5];

for (int i = 0; i < values.Length; i++)
    values[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {values.Length}, sizeof(nint): {sizeof(nint)}");
for (int i = 0; i < values.Length; i++)
    Console.WriteLine($"  values[{i}] = {values[i]}");

// Also test nuint
Span<nuint> unsigned = stackalloc nuint[3];
unsigned[0] = 100;
unsigned[1] = 200;
unsigned[2] = 300;

Console.WriteLine($"\nSpan<nuint> length: {unsigned.Length}");
for (int i = 0; i < unsigned.Length; i++)
    Console.WriteLine($"  unsigned[{i}] = {unsigned[i]}");

